SELECT pattern_type_name, created_at
FROM pattern_types
ORDER BY created_at DESC;

SELECT pattern_type_name, description
FROM pattern_types
WHERE complexity = 1;

SELECT proposition_name, description
FROM propositions
WHERE created_at > '2023-05-01 00:00:00';

SELECT COUNT(proposition_id) AS proposition_count
FROM propositions
WHERE created_at > '2023-05-01 00:00:00';

SELECT COUNT(utterance_id) AS utterance_count
FROM utterances
WHERE pattern_type_id = 0;

SELECT output_landmark
FROM output_landmarks
WHERE utterance_id = 0;
